//Weighted Shortest path - 1
// Basic Dijkstra
#include&lt;iostream&gt;
#include&lt;vector&gt;
#include&lt;queue&gt;
#include&lt;limits.h&gt;

using namespace std;

struct Edge {
    int v, c;
    Edge(int vv, int cc) : v(vv), c(cc) {}
};

using P = pair&lt;int,int&gt;; //distance, vertex
using VVP = vector&lt;vector&lt;Edge&gt;&gt;;

vector&lt;int&gt; dijkstra(const VVP& g, int s){
    int n = g.size();
    vector&lt;int&gt; d(n, INT_MAX);
    vector&lt;bool&gt; marked(n,false);
    priority_queue&lt;P, vector&lt;P&gt;, greater&lt;P&gt;&gt; pq;
    d[s] = 0;
    pq.push({d[s],s});
    while (not pq.empty()){
        int u = pq.top().second;
        pq.pop();
        if (not marked[u]){
            marked[u] = true;
            for (int i = 0; i &lt; g[u].size(); ++i){
                int v = g[u][i].v;
                int c = g[u][i].c;
                if (d[v] &gt; d[u] + c){
                    d[v] = d[u] + c;
                    pq.push(P({d[v],v}));
                }
            }
        }
    }
    return d;
} 

int main(){
    int n, m;
    while(cin &gt;&gt; n &gt;&gt; m){
        VVP g(n);
        for (int k = 0; k &lt; m; ++k){
            int u, v, c;
            cin &gt;&gt; u &gt;&gt; v &gt;&gt; c;
            g[u].push_back(Edge(v,c));
        }
        int x, y;
        cin &gt;&gt; x &gt;&gt; y;
        vector&lt;int&gt; d = dijkstra(g, x);
        if (d[y] == INT_MAX) cout &lt;&lt; "no path from " &lt;&lt; x &lt;&lt; " to " &lt;&lt; y &lt;&lt; endl;
        else cout &lt;&lt; d[y] &lt;&lt; endl;
    }
}






