//STL - Satistical measures
#include&lt;iostream&gt;
#include&lt;queue&gt;
#include&lt;limits&gt;
#include&lt;iomanip&gt;

using namespace std;

const auto MININFTY = numeric_limits&lt;int&gt;::lowest();

int main(){
    string op;
    priority_queue&lt;int,vector&lt;int&gt;,greater&lt;int&gt;&gt; q;
    int sum = 0;
    int max = MININFTY;
    while (cin &gt;&gt; op){
        if (op == "delete"){ 
            if (not q.empty()){
                sum -=q.top();
                q.pop();
                if (q.empty()) max = MININFTY;
            }
        }
        else{// case of "number"
            int value;
            cin &gt;&gt; value;
            q.push(value);
            sum +=value;
            if (value &gt; max) max = value; 
        } 
        int sz = q.size();
        if (sz == 0) cout &lt;&lt; "no elements" &lt;&lt; endl;
        else{
            double avg = double(sum) / sz;
            cout &lt;&lt; "minimum: " &lt;&lt; q.top();
            cout &lt;&lt; ", maximum: " &lt;&lt; max;
            cout &lt;&lt; ", average: " &lt;&lt; fixed &lt;&lt; setprecision(4) &lt;&lt; avg &lt;&lt; endl;
        }
    }
}






