    for (int k = 0 ; k &lt; N_DIRS; ++k){
        Pos q(p.i+DIRS[k].i, p.j + DIRS[k].j);
        if (within_range(q, n, m) and !visited[q.i][q.j] and map[q.i][q.j] != 'X') 
            if(dfs(map, visited, q)) return true;
    }
    return false;
}

