// Forest
#include&lt;iostream&gt;
#include&lt;vector&gt;

using namespace std;
using VVI = vector&lt;vector&lt;int&gt;&gt;;
using VB = vector&lt;bool&gt;;
using VI = vector&lt;int&gt;;

bool cyclic(const VVI& g, int v, VB& visited, VI& parent){
    if (visited[v]) return true;
    visited[v] = true;
    for (int u : g[v]){
        if (parent[v] != u){
            parent[u] = v;
            if (cyclic(g, u, visited, parent)) return true;
        }
    }
    return false;
}

int count_trees(const VVI& g){
    int n = g.size();
    int n_trees = 0;
    VB visited(n, false);
    VI parent(n, -1);
    for (int v = 0; v &lt; n; ++v){
        if (not visited[v]){
            if (cyclic(g, v, visited,parent)) return -1;
            else ++n_trees;
        }
    }
    return n_trees;
}

int main(){
    int n, m;
    while (cin &gt;&gt; n &gt;&gt; m){
        VVI g(n);
        for (int k = 0; k &lt; m; ++k){
            int u,v;
            cin &gt;&gt; u &gt;&gt; v;
            g[u].push_back(v);
            g[v].push_back(u);
        }
        int n_trees = count_trees(g); // -1 if g is not a tree
        if (n_trees == -1 ) cout &lt;&lt; "no" &lt;&lt; endl;
        else                cout &lt;&lt; n_trees &lt;&lt; endl;
    }
}







